render.css:
.dashed-list { display: flex; flex-direction: column; gap: 20px; }
.dashed-item { display: block; }
.dashed-header { display: flex; justify-content: space-between; margin-bottom: 6px; font-size: 13px; color: var(--ct-text-muted); }
.dashed-header span:last-child { color: var(--ct-text-strong); font-weight: 600; }
.dashed-track { height: 6px; background: var(--ct-surface-2); border-radius: 3px; overflow: hidden; }
.dashed-fill { height: 100%; background: repeating-linear-gradient(90deg, var(--ct-text-strong) 0 4px, transparent 4px 8px); border-radius: 3px; }
